/* ==================== GLOBAL RESET ==================== */

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

:root {
    /* Color Palette - Dark Theme (Default) */
    --bg-primary: #1a2332;
    --bg-secondary: #243447;
    --bg-card: #2a3f5f;
    --text-primary: #ffffff;
    --text-secondary: #b0c4de;
    --accent-teal: #4ecdc4;
    --accent-yellow: #ffd166;
    --accent-pink: #ff6b9d;
    --accent-purple: #c77dff;
    --accent-green: #06ffa5;
    --accent-red: #ff4757;
    --border-color: #3d5a80;
}

body {
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    background: var(--bg-primary);
    color: var(--text-primary);
    overflow-x: hidden;
    transition: background 0.5s ease, color 0.5s ease;
}

/* Theme Transition Animations */
.app-container,
.sidebar,
.main-content,
.card,
.nav-item,
.theme-section {
    transition: all 0.5s ease;
}

button,
.filter-btn {
    transition: all 0.3s ease;
}

.chart-container canvas {
    transition: all 0.5s ease;
}

/* ==================== DEVICE CONTROL ==================== */

.device-control {
    padding: 20px;
}

.device-item {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 15px;
    background: var(--bg-secondary);
    border-radius: 10px;
    margin-bottom: 10px;
}

.device-info {
    display: flex;
    flex-direction: column;
}

.device-name {
    font-weight: 600;
    color: var(--text-primary);
    margin-bottom: 5px;
}

.device-status {
    font-size: 0.9rem;
    color: var(--text-secondary);
}

.device-status.online {
    color: var(--accent-green);
}

.device-status.offline {
    color: var(--accent-red);
}

/* Toggle Switch */
.switch {
    position: relative;
    display: inline-block;
    width: 60px;
    height: 34px;
}

.switch input {
    opacity: 0;
    width: 0;
    height: 0;
}

.slider {
    position: absolute;
    cursor: pointer;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background-color: #ccc;
    transition: .4s;
    border-radius: 34px;
}

.slider:before {
    position: absolute;
    content: "";
    height: 26px;
    width: 26px;
    left: 4px;
    bottom: 4px;
    background-color: white;
    transition: .4s;
    border-radius: 50%;
}

input:checked + .slider {
    background-color: var(--accent-teal);
}

input:checked + .slider:before {
    transform: translateX(26px);
}

/* ==================== APPLIANCES TAB STYLES ==================== */

.appliances-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(250px, 1fr));
    gap: 20px;
    padding: 20px;
}

.appliance-card {
    background: var(--bg-secondary);
    border-radius: 10px;
    padding: 20px;
    cursor: pointer;
    transition: all 0.3s ease;
    border: 2px solid transparent;
}

.appliance-card:hover {
    border-color: var(--accent-teal);
    transform: translateY(-2px);
}

.appliance-card.selected {
    border-color: var(--accent-teal);
    background: var(--bg-card);
}

.appliance-card-name {
    font-weight: 600;
    margin-bottom: 10px;
    color: var(--text-primary);
}

.appliance-card-status {
    font-size: 0.9rem;
    color: var(--text-secondary);
    margin-bottom: 5px;
}

.appliance-card-power {
    font-size: 1.2rem;
    font-weight: bold;
    color: var(--accent-teal);
}

/* Device Controls */
#deviceControls {
    padding: 20px;
}

.no-device-selected {
    text-align: center;
    color: var(--text-secondary);
    padding: 40px;
}

.device-selected {
    display: block;
}

.selected-device-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 20px;
    padding-bottom: 15px;
    border-bottom: 2px solid var(--border-color);
}

.selected-device-header h4 {
    color: var(--text-primary);
    margin: 0;
}

.selected-device-status {
    padding: 5px 15px;
    border-radius: 20px;
    font-size: 0.9rem;
    font-weight: 600;
    background: var(--accent-green);
    color: white;
}

.device-details-section,
.instant-control-section,
.scheduler-section {
    margin-bottom: 30px;
}

.device-details-section h5,
.instant-control-section h5,
.scheduler-section h5 {
    color: var(--text-primary);
    margin-bottom: 15px;
    font-size: 1rem;
    text-transform: uppercase;
    letter-spacing: 1px;
}

/* Device Details */
.device-details {
    padding: 20px;
}

.detail-item {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 10px 0;
    border-bottom: 1px solid var(--border-color);
}

.detail-item:last-child {
    border-bottom: none;
}

.detail-label {
    font-weight: 500;
    color: var(--text-secondary);
}

.detail-value {
    font-weight: 600;
    color: var(--text-primary);
}

/* Instant Control */
.instant-control {
    padding: 20px;
}

.control-item {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 15px;
    background: var(--bg-secondary);
    border-radius: 10px;
    margin-bottom: 10px;
}

.control-label {
    font-weight: 600;
    color: var(--text-primary);
}

.control-buttons {
    display: flex;
    gap: 10px;
}

.control-btn {
    padding: 8px 20px;
    border: none;
    border-radius: 5px;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.3s ease;
}

.control-btn.on {
    background: var(--accent-green);
    color: white;
}

.control-btn.on:hover {
    background: #05d686;
}

.control-btn.off {
    background: var(--accent-red);
    color: white;
}

.control-btn.off:hover {
    background: #ff3838;
}

/* Time Scheduler */
.scheduler {
    padding: 20px;
}

.schedule-form {
    background: var(--bg-secondary);
    padding: 20px;
    border-radius: 10px;
    margin-bottom: 20px;
}

.form-group {
    margin-bottom: 15px;
}

.form-group label {
    display: block;
    margin-bottom: 5px;
    color: var(--text-secondary);
    font-weight: 500;
}

.time-input, .action-select {
    width: 100%;
    padding: 8px 12px;
    background: var(--bg-card);
    border: 1px solid var(--border-color);
    border-radius: 5px;
    color: var(--text-primary);
}

.schedule-btn {
    width: 100%;
    padding: 10px;
    background: var(--accent-teal);
    color: white;
    border: none;
    border-radius: 5px;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.3s ease;
}

.schedule-btn:hover {
    background: #3db8af;
}

.schedule-list {
    max-height: 200px;
    overflow-y: auto;
}

.schedule-item {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 10px;
    background: var(--bg-secondary);
    border-radius: 5px;
    margin-bottom: 10px;
}

.schedule-info {
    flex: 1;
}

.schedule-time {
    font-weight: 600;
    color: var(--text-primary);
}

.schedule-action {
    font-size: 0.9rem;
    color: var(--text-secondary);
}

.schedule-delete {
    padding: 5px 10px;
    background: var(--accent-red);
    color: white;
    border: none;
    border-radius: 3px;
    cursor: pointer;
    font-size: 0.8rem;
}

/* ==================== APP CONTAINER ==================== */

.app-container {
    display: flex;
    min-height: 100vh;
    position: relative;
    z-index: 1;
}

/* ==================== SIDEBAR ==================== */

.sidebar {
    width: 250px;
    background: #1a1f3a;
    padding: 30px 20px;
    display: flex;
    flex-direction: column;
    position: fixed;
    height: 100vh;
    border-right: 1px solid var(--border-color);
}

.logo {
    margin-bottom: 50px;
}

.logo h1 {
    font-size: 1.5em;
    font-weight: 600;
    letter-spacing: 2px;
    color: var(--text-primary);
}

.beta-badge {
    display: inline-block;
    background: var(--accent-pink);
    color: white;
    font-size: 0.7em;
    padding: 3px 8px;
    border-radius: 4px;
    margin-left: 10px;
    font-weight: bold;
}

.nav-menu {
    display: flex;
    flex-direction: column;
    gap: 5px;
}

.nav-item {
    display: flex;
    align-items: center;
    gap: 15px;
    padding: 15px 20px;
    color: var(--text-secondary);
    text-decoration: none;
    border-radius: 8px;
    transition: all 0.3s ease;
    font-size: 0.95em;
}

.nav-item:hover {
    background: var(--bg-secondary);
    color: var(--text-primary);
}

.nav-item.active {
    background: var(--bg-secondary);
    color: var(--text-primary);
    border-left: 4px solid var(--accent-teal);
}

.nav-item .icon {
    font-size: 1.2em;
}

/* ==================== THEME TOGGLE ==================== */

.theme-section {
    margin-top: auto;
    padding: 20px 15px;
    border-top: 1px solid var(--border-color);
    display: flex;
    justify-content: center;
}

.theme-toggle {
    width: 50px;
    height: 50px;
    border-radius: 50%;
    border: 2px solid var(--border-color);
    background: var(--bg-secondary);
    cursor: pointer;
    font-size: 1.5em;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: all 0.3s ease;
}

.theme-toggle:hover {
    transform: scale(1.1);
    border-color: var(--accent-teal);
    box-shadow: 0 0 15px var(--accent-teal);
}

.theme-icon {
    transition: transform 0.3s ease;
}

/* ==================== MAIN CONTENT ==================== */

.main-content {
    flex: 1;
    margin-left: 250px;
    background: var(--bg-primary);
    padding: 30px;
}

/* ==================== HEADER ==================== */

.header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 30px;
}

.header h2 {
    font-size: 2em;
    font-weight: 400;
    color: var(--text-primary);
}

.header-right {
    display: flex;
    align-items: center;
    gap: 30px;
}

.time-filter {
    display: flex;
    gap: 0;
    background: var(--bg-secondary);
    border-radius: 25px;
    padding: 5px;
}

.filter-btn {
    padding: 10px 20px;
    background: transparent;
    border: none;
    color: var(--text-secondary);
    font-size: 0.85em;
    font-weight: 600;
    cursor: pointer;
    border-radius: 20px;
    transition: all 0.3s ease;
    position: relative;
}

.filter-btn:hover {
    color: var(--text-primary);
    background: rgba(255, 255, 255, 0.05);
    transform: translateY(-1px);
}

.filter-btn.active {
    background: var(--bg-card);
    color: var(--text-primary);
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.2);
    transform: scale(1.05);
}

.filter-btn:active {
    transform: scale(0.95);
}

.filter-btn.loading {
    opacity: 0.7;
    pointer-events: none;
}

.filter-btn.loading::after {
    content: '...';
    margin-left: 5px;
    font-size: 0.8em;
}

.date-display {
    color: var(--text-secondary);
    font-size: 0.95em;
}

/* ==================== DASHBOARD GRID ==================== */

.dashboard-grid {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 25px;
}

/* ==================== CARD STYLES ==================== */

.card {
    background: var(--bg-card);
    border-radius: 15px;
    padding: 25px;
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.3);
    transition: transform 0.3s ease;
}

.card:hover {
    transform: translateY(-5px);
}

.card-title {
    font-size: 0.85em;
    font-weight: 600;
    color: var(--text-secondary);
    letter-spacing: 1px;
    margin-bottom: 20px;
    text-transform: uppercase;
}

/* ==================== COST PREDICTED ==================== */

.chart-container {
    position: relative;
    height: 200px;
    display: flex;
    align-items: center;
    justify-content: center;
}

.chart-center-text {
    position: absolute;
    text-align: center;
    pointer-events: none;
}

.total-label {
    font-size: 0.9em;
    color: var(--text-secondary);
}

.total-value {
    font-size: 2em;
    font-weight: bold;
    color: var(--text-primary);
    margin-top: 5px;
}

.chart-legend {
    display: flex;
    justify-content: center;
    gap: 30px;
    margin-top: 20px;
}

.legend-item {
    display: flex;
    align-items: center;
    gap: 8px;
    font-size: 0.9em;
    color: var(--text-secondary);
}

.legend-dot {
    width: 12px;
    height: 12px;
    border-radius: 3px;
}

.legend-dot.electricity {
    background: var(--accent-teal);
}

.legend-dot.gas {
    background: var(--accent-yellow);
}

/* ==================== CHANGE IN COST ==================== */

.cost-comparison {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 20px 0;
}

.cost-bar-container {
    display: flex;
    gap: 30px;
    flex: 1;
}

.cost-bar {
    text-align: center;
}

.bar-value {
    font-size: 1.8em;
    font-weight: bold;
    color: var(--accent-teal);
    margin-bottom: 10px;
}

.bar-label {
    font-size: 0.85em;
    color: var(--text-secondary);
}

.cost-change {
    text-align: center;
    padding: 20px;
}

.change-icon {
    font-size: 2em;
    color: var(--accent-red);
    margin-bottom: 5px;
}

.change-percentage {
    font-size: 2em;
    font-weight: bold;
    color: var(--accent-red);
    margin-bottom: 5px;
}

.change-label {
    font-size: 0.75em;
    color: var(--text-secondary);
    letter-spacing: 1px;
}

/* ==================== USAGE ESTIMATE ==================== */

.usage-stats {
    display: flex;
    justify-content: space-between;
    margin-bottom: 20px;
}

.stat-item {
    display: flex;
    flex-direction: column;
    gap: 5px;
}

.stat-label {
    font-size: 0.85em;
    color: var(--text-secondary);
}

.stat-value {
    font-size: 1.1em;
    font-weight: bold;
    color: var(--text-primary);
}

/* ==================== ACTIVE APPLIANCES ==================== */

.appliances-list {
    display: flex;
    flex-direction: column;
    gap: 15px;
}

.appliance-item {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 0;
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.appliance-name {
    display: flex;
    align-items: center;
    gap: 10px;
    color: var(--text-primary);
}

.appliance-bar {
    width: 120px;
    height: 8px;
    background: rgba(255, 255, 255, 0.1);
    border-radius: 4px;
    overflow: hidden;
    margin-right: 10px;
}

.appliance-bar-fill {
    height: 100%;
    border-radius: 4px;
    transition: width 0.3s ease;
}

.appliance-value {
    font-weight: 600;
    color: var(--text-primary);
    min-width: 60px;
    text-align: right;
}

/* ==================== SMART SAVINGS MONITOR ==================== */

.savings-summary {
    margin-bottom: 20px;
}

.savings-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 20px;
}

.savings-item {
    flex: 1;
    text-align: center;
    padding: 15px;
    border-radius: 10px;
    background: rgba(255, 255, 255, 0.05);
}

.savings-item.waste {
    border: 2px solid var(--accent-red);
    background: rgba(255, 71, 87, 0.1);
}

.savings-item.saved {
    border: 2px solid var(--accent-green);
    background: rgba(6, 255, 165, 0.1);
}

.savings-label {
    font-size: 0.85em;
    color: var(--text-secondary);
    margin-bottom: 5px;
}

.savings-amount {
    font-size: 1.8em;
    font-weight: bold;
    margin-bottom: 5px;
}

.savings-item.waste .savings-amount {
    color: var(--accent-red);
}

.savings-item.saved .savings-amount {
    color: var(--accent-green);
}

.savings-desc {
    font-size: 0.75em;
    color: var(--text-secondary);
}

.savings-divider {
    width: 2px;
    height: 60px;
    background: rgba(255, 255, 255, 0.1);
    margin: 0 15px;
}

.net-savings {
    text-align: center;
    padding: 15px;
    background: var(--bg-secondary);
    border-radius: 10px;
    margin-top: 10px;
}

.net-label {
    font-size: 0.85em;
    color: var(--text-secondary);
    margin-bottom: 5px;
}

.net-amount {
    font-size: 2em;
    font-weight: bold;
    color: var(--accent-teal);
    margin-bottom: 5px;
}

.net-percentage {
    font-size: 1em;
    color: var(--accent-green);
    font-weight: 600;
}

.savings-amount, .net-amount, .net-percentage {
    display: block !important;
    visibility: visible !important;
}

#savingsChart {
    display: block !important;
    visibility: visible !important;
    height: 200px !important;
}

.device-savings-list {
    margin-top: 20px;
    max-height: 200px;
    overflow-y: auto;
}

.device-savings-item {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px;
    margin-bottom: 8px;
    background: rgba(255, 255, 255, 0.03);
    border-radius: 8px;
    border-left: 3px solid transparent;
}

.device-info {
    flex: 1;
}

.device-name {
    font-size: 0.9em;
    color: var(--text-primary);
    font-weight: 600;
    margin-bottom: 3px;
}

.device-power {
    font-size: 0.75em;
    color: var(--text-secondary);
}

.waste-power {
    color: var(--accent-red);
    margin-right: 10px;
}

.saved-power {
    color: var(--accent-green);
}

.device-savings {
    font-size: 0.95em;
    font-weight: bold;
    min-width: 60px;
    text-align: right;
}

.device-savings.positive {
    color: var(--accent-green);
}

.device-savings.negative {
    color: var(--accent-red);
}

.no-devices {
    text-align: center;
    color: var(--text-secondary);
    font-size: 0.85em;
    padding: 20px;
}

/* ==================== TAB PANES ==================== */

.tab-pane {
    display: none !important;
}

.tab-pane.active {
    display: grid !important;
}

.main-content > .tab-pane {
    display: none !important;
}

.main-content > .tab-pane.active {
    display: grid !important;
}

.card.full-width {
    grid-column: 1 / -1;
}

.chart-container.large {
    height: 300px;
}

/* ==================== COST ANALYSIS ==================== */

.cost-analysis {
    padding: 10px 0;
}

.cost-summary {
    display: flex;
    gap: 20px;
    margin-bottom: 30px;
    flex-wrap: wrap;
}

.cost-card {
    display: flex;
    align-items: center;
    gap: 15px;
    padding: 20px 25px;
    background: var(--bg-secondary);
    border-radius: 12px;
    flex: 1;
    min-width: 200px;
}

.cost-icon {
    font-size: 2em;
}

.cost-info {
    display: flex;
    flex-direction: column;
}

.cost-label {
    font-size: 0.85em;
    color: var(--text-secondary);
    margin-bottom: 5px;
}

.cost-value {
    font-size: 1.5em;
    font-weight: bold;
    color: var(--text-primary);
}

.device-cost-list {
    display: flex;
    flex-direction: column;
    gap: 10px;
}

.device-cost-item {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 15px;
    background: rgba(255, 255, 255, 0.03);
    border-radius: 8px;
}

.device-cost-item .device-name {
    font-size: 0.95em;
    color: var(--text-primary);
}

.device-cost-value {
    font-size: 1.1em;
    font-weight: bold;
    color: var(--accent-teal);
}

/* ==================== APPLIANCES TAB ==================== */

.appliances-cards {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
    gap: 20px;
}

.appliance-card {
    background: var(--bg-secondary);
    border-radius: 12px;
    padding: 20px;
    transition: transform 0.3s ease;
}

.appliance-card:hover {
    transform: translateY(-5px);
}

.appliance-card-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 15px;
}

.appliance-card-name {
    font-size: 1.1em;
    font-weight: 600;
    color: var(--text-primary);
}

.appliance-card-status {
    font-size: 0.75em;
    padding: 4px 10px;
    border-radius: 12px;
    font-weight: 600;
}

.appliance-card-status.active {
    background: rgba(6, 255, 165, 0.2);
    color: var(--accent-green);
}

.appliance-card-status.inactive {
    background: rgba(255, 255, 255, 0.1);
    color: var(--text-secondary);
}

.appliance-card-power {
    font-size: 1.8em;
    font-weight: bold;
    color: var(--text-primary);
    margin-bottom: 5px;
}

.appliance-card-mode {
    font-size: 0.85em;
    color: var(--text-secondary);
}

.appliance-status-list {
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.status-item {
    display: flex;
    align-items: center;
    gap: 15px;
    padding: 12px 15px;
    background: rgba(255, 255, 255, 0.03);
    border-radius: 8px;
}

.status-indicator {
    width: 12px;
    height: 12px;
    border-radius: 50%;
}

.status-indicator.on {
    background: var(--accent-green);
    box-shadow: 0 0 10px var(--accent-green);
}

.status-indicator.off {
    background: var(--text-secondary);
}

.status-name {
    flex: 1;
    font-size: 0.95em;
    color: var(--text-primary);
}

.status-power {
    font-size: 0.9em;
    color: var(--text-secondary);
}

/* ==================== ROOMS TAB ==================== */

.rooms-summary {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
    gap: 20px;
    margin-bottom: 30px;
}

.room-card {
    background: var(--bg-secondary);
    border-radius: 12px;
    padding: 25px 20px;
    text-align: center;
    transition: transform 0.3s ease;
}

.room-card:hover {
    transform: translateY(-5px);
}

.room-icon {
    font-size: 2.5em;
    margin-bottom: 15px;
}

.room-name {
    font-size: 1em;
    font-weight: 600;
    color: var(--text-primary);
    margin-bottom: 10px;
}

.room-usage {
    font-size: 1.3em;
    font-weight: bold;
    color: var(--accent-teal);
}

.room-details-list {
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.room-detail-item {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 15px;
    background: rgba(255, 255, 255, 0.03);
    border-radius: 8px;
}

.room-detail-name {
    font-size: 0.95em;
    color: var(--text-primary);
}

.room-detail-usage {
    font-size: 1em;
    font-weight: bold;
    color: var(--accent-teal);
}

/* ==================== RESPONSIVE DESIGN ==================== */

@media (max-width: 1200px) {
    .dashboard-grid {
        grid-template-columns: 1fr;
    }
}

@media (max-width: 900px) {
    .sidebar {
        width: 70px;
        padding: 20px 10px;
    }

    .logo h1,
    .beta-badge,
    .nav-item span:not(.icon) {
        display: none;
    }

    .nav-item {
        justify-content: center;
        padding: 15px;
    }

    .main-content {
        margin-left: 70px;
    }
}

@media (max-width: 600px) {
    .header {
        flex-direction: column;
        gap: 15px;
        align-items: flex-start;
    }

    .cost-comparison {
        flex-direction: column;
        gap: 20px;
    }
}

/* ==================== LIGHT THEME ==================== */

body[data-theme="light"] {
    --bg-primary: #f5f7fa;
    --bg-secondary: #e8ecf1;
    --bg-card: #ffffff;
    --text-primary: #1a2332;
    --text-secondary: #5a6a7a;
    --accent-teal: #20b2aa;
    --accent-yellow: #f0c040;
    --accent-pink: #e85a7d;
    --accent-purple: #9b59b6;
    --accent-green: #2ecc71;
    --accent-red: #e74c3c;
    --border-color: #d0d7de;
}

